using Microsoft.EntityFrameworkCore;

class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(b =>
        {
            // Breaking change 1: Default discriminator property renamed "$type".
            // Existing documents use "Discriminator", so pin the old name.
            b.HasDiscriminator<string>("Discriminator");

            // Breaking change 2: id is no longer synthesized as "{Discriminator}|{Key}".
            // Existing documents store id = "Blog|<key>", so use a value converter
            // that keeps the application-level Id as the raw key while persisting
            // the prefixed value that Cosmos already has on disk.
            b.Property(e => e.Id)
                .HasConversion(
                    v => v.StartsWith("Blog|") ? v : $"Blog|{v}",
                    v => v.StartsWith("Blog|") ? v.Substring("Blog|".Length) : v);

            // Breaking change 3: HasIndex() now throws for the Cosmos provider
            // (it was silently ignored before). Removed the previous HasIndex call.
        });
    }
}

class Blog { public string Id { get; set; } public string Name { get; set; } }

