using Microsoft.EntityFrameworkCore;

class SyncJob
{
    // Breaking change 4: Cosmos provider no longer supports synchronous I/O.
    // ToList() / SaveChanges() throw; use async equivalents.
    async Task RunAsync(BlogContext context)
    {
        var blogs = await context.Blogs.ToListAsync();
        foreach (var b in blogs) { b.Name = b.Name.Trim(); }
        await context.SaveChangesAsync();
    }
}

